import heapq

def solve(grid: list[list[int]], k: int) -> int:
    m, n = len(grid), len(grid[0])
    # We will use a priority queue to explore states in order of increasing cost.
    # Each state is (cost, i, j, remaining_k)
    heap = []
    heapq.heappush(heap, (0, 0, 0, k))

    # To avoid revisiting the same cell with the same or worse remaining_k and higher cost,
    # we keep track of the minimal cost for each (i, j, remaining_k).
    visited = {}
    visited[(0, 0, k)] = 0

    directions = [(0, 1), (1, 0)]  # right and down

    while heap:
        cost, i, j, remaining_k = heapq.heappop(heap)
        if i == m - 1 and j == n - 1:
            return cost

        if cost > visited.get((i, j, remaining_k), float('inf')):
            continue

        # Explore normal moves (right and down)
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n:
                new_cost = cost + grid[ni][nj]
                if (ni, nj, remaining_k) not in visited or new_cost < visited[(ni, nj, remaining_k)]:
                    visited[(ni, nj, remaining_k)] = new_cost
                    heapq.heappush(heap, (new_cost, ni, nj, remaining_k))

        # Explore teleport moves if remaining_k > 0
        if remaining_k > 0:
            for x in range(m):
                for y in range(n):
                    if (x != i or y != j) and grid[x][y] <= grid[i][j]:
                        if (x, y, remaining_k - 1) not in visited or cost < visited[(x, y, remaining_k - 1)]:
                            visited[(x, y, remaining_k - 1)] = cost
                            heapq.heappush(heap, (cost, x, y, remaining_k - 1))

    return -1  # should not reach here if grid is valid
